import type { StrategyBacktestResult, Trade } from '@/types';

function getSortedTrades(trades: Trade[]): Trade[] {
  const sortedTrades = trades.slice().sort((a, b) => (a.profit_ratio ?? 0) - (b.profit_ratio ?? 0));
  return sortedTrades;
}

function getBestPair(trades: Trade[]) {
  const value = trades[trades.length - 1];
  if (!value) {
    return 'N/A';
  }
  return `${value.pair} ${formatPercent(value.profit_ratio, 2)}`;
}

function getWorstPair(trades: Trade[]) {
  const value = trades[0];
  if (!value) {
    return 'N/A';
  }
  return `${value.pair} ${formatPercent(value.profit_ratio, 2)}`;
}

function useFormatPriceStake(stake_currency_decimals: number, stake_currency: string) {
  const formatPriceStake = (price) => {
    return `${formatPrice(price, stake_currency_decimals)} ${stake_currency}`;
  };
  return formatPriceStake;
}

export function generateBacktestMetricRows(result: StrategyBacktestResult) {
  const sortedTrades = getSortedTrades(result.trades);
  const bestPair = getBestPair(sortedTrades);
  const worstPair = getWorstPair(sortedTrades);
  const pairSummary = result.results_per_pair[result.results_per_pair.length - 1];

  const formatPriceStake = useFormatPriceStake(
    result.stake_currency_decimals,
    result.stake_currency,
  );

  // Transpose Result into readable format
  const shortMetrics =
    result.trade_count_short && result.trade_count_short > 0
      ? [
          { '___ ': '___' },
          {
            'Long / Short': `${result.trade_count_long} / ${result.trade_count_short}`,  // Lưu ý: key không dịch vì dùng làm field id
          },
          {
            'Tổng LN Long': `${formatPercent(
              result.profit_total_long || 0,
            )} | ${formatPriceStake(result.profit_total_long_abs)}`,
          },
          {
            'Tổng LN Short': `${formatPercent(
              result.profit_total_short || 0,
            )} | ${formatPriceStake(result.profit_total_short_abs)}`,
          },
        ]
      : [];

  const _b_append = ` (số dư ví)`;
  const walletBalanceMetrics = result.wallet_stats
    ? [
        { '--- Chỉ số số dư ví ---': '' },
        {
          [`Drawdown tối đa${_b_append}`]: formatPercent(result.wallet_stats.max_drawdown_account),
        },
        {
          [`Drawdown tối đa tuyệt đối${_b_append}`]: formatPriceStake(result.wallet_stats.max_drawdown_abs),
        },
        {
          [`Thời gian drawdown${_b_append}`]: result.wallet_stats.drawdown_duration ?? 'N/A',
        },
        {
          [`LN khi bắt đầu | kết thúc drawdown${_b_append}`]: `${formatPriceStake(result.wallet_stats.max_drawdown_high)} | ${formatPriceStake(
            result.wallet_stats.max_drawdown_low,
          )}`,
        },
        // { 'Max Drawdown dates (wallet balance)': formatPercent(result.wallet_stats.max_drawdown_account) },
        {
          [`Bắt đầu drawdown${_b_append}`]: timestampms(result.wallet_stats?.drawdown_start_ts ?? 0),
        },
        { [`Kết thúc drawdown${_b_append}`]: timestampms(result.wallet_stats?.drawdown_end_ts ?? 0) },
        {
          [`Sortino${_b_append}`]: formatNumber(result.wallet_stats.sortino, 2),
        },
        {
          [`Sharpe${_b_append}`]: formatNumber(result.wallet_stats.sharpe, 2),
        },
        {
          [`Calmar${_b_append}`]: formatNumber(result.wallet_stats.calmar, 2),
        },
      ]
    : [];

  const tmp = [
    {
      'Tổng lợi nhuận': `${formatPercent(result.profit_total)} | ${formatPriceStake(
        result.profit_total_abs,
      )}`,
    },
    {
      CAGR: `${result.cagr ? formatPercent(result.cagr) : 'N/A'}`,
    },
    {
      Sortino: formatNumber(result.sortino, 2),
    },
    {
      Sharpe: formatNumber(result.sharpe, 2),
    },
    {
      Calmar: formatNumber(result.calmar, 2),
    },
    {
      'System Quality Number (SQN)': formatNumber(result.sqn, 2),
    },
    {
      [`Expectancy ${result.expectancy_ratio ? '(ratio)' : ''}`]: `${
        result.expectancy
          ? result.expectancy_ratio
            ? `${formatNumber(result.expectancy, 2)} (${formatNumber(result.expectancy_ratio, 2)})`
            : formatNumber(result.expectancy, 2)
          : 'N/A'
      }`,
    },
    {
      'Hệ số lợi nhuận': formatNumber(result.profit_factor, 3),
    },
    {
      'Tổng lệnh / Lệnh tb/ngày': `${result.total_trades} / ${formatNumber(result.trades_per_day, 2)}`,
    },
    // { 'First trade': result.backtest_fi },
    // { 'First trade Pair': result.backtest_best_day },
    {
      'Ngày tốt nhất': `${formatPercent(result.backtest_best_day, 2)} | ${formatPriceStake(
        result.backtest_best_day_abs,
      )}`,
    },
    {
      'Ngày tệ nhất': `${formatPercent(result.backtest_worst_day, 2)} | ${formatPriceStake(
        result.backtest_worst_day_abs,
      )}`,
    },

    {
      'Thắng/Hòa/Thua': `${pairSummary?.wins} / ${pairSummary?.draws} / ${pairSummary?.losses} ${
        isNotUndefined(pairSummary?.winrate)
          ? '(TL: ' +
            formatPercent(
              result.results_per_pair[result.results_per_pair.length - 1]?.winrate ?? 0,
              2,
            ) +
            ')'
          : ''
      }`,
    },
    {
      'Ngày thắng/hòa/thua': `${result.winning_days} / ${result.draw_days} / ${result.losing_days}`,
    },
    {
      // TODO: min/max/avg trade duration should be aligned with the terminal output
      'TG giữ lệnh thắng (min)': humanizeDurationFromSeconds(result.winner_holding_min_s),
    },
    {
      'TG giữ lệnh thắng (tb)': humanizeDurationFromSeconds(result.winner_holding_avg_s),
    },
    {
      'TG giữ lệnh thắng (max)': humanizeDurationFromSeconds(result.winner_holding_max_s),
    },
    {
      'TG giữ lệnh thua (min)': humanizeDurationFromSeconds(result.loser_holding_min_s),
    },
    {
      'TG giữ lệnh thua (tb)': humanizeDurationFromSeconds(result.loser_holding_avg_s),
    },
    {
      'TG giữ lệnh thua (max)': humanizeDurationFromSeconds(result.loser_holding_max_s),
    },
    {
      'Thắng liên tiếp max / Thua liên tiếp max':
        result.max_consecutive_wins === undefined
          ? 'N/A'
          : `${result.max_consecutive_wins} / ${result.max_consecutive_losses}`,
    },
    { 'Tín hiệu vào bị từ chối': result.rejected_signals },
    {
      'Timeout vào/ra lệnh': `${result.timedout_entry_orders} / ${result.timedout_exit_orders}`,
    },
    {
      'Lệnh vào bị hủy': result.canceled_trade_entries ?? 'N/A',
    },
    {
      'Lệnh vào đã hủy': result.canceled_entry_orders ?? 'N/A',
    },
    {
      'Lệnh vào thay thế': result.replaced_entry_orders ?? 'N/A',
    },

    ...shortMetrics,

    { ___: '___' },
    {
      'Số dư min/max (lệnh đã đóng)': `${formatPriceStake(result.csum_min)} / ${formatPriceStake(result.csum_max)}`,
    },
    {
      'Số dư min/max (ví)': `${formatPriceStake(result.wallet_stats?.low_balance)} / ${formatPriceStake(result.wallet_stats?.high_balance)}`,
    },
    { 'Biến động thị trường': formatPercent(result.market_change) },
    { '___  ': '___' },
    {
      'Drawdown tối đa (tài khoản)': formatPercent(result.max_drawdown_account),
    },
    {
      'Drawdown tối đa (tuyệt đối)': formatPriceStake(result.max_drawdown_abs),
    },
    {
      'Thời gian drawdown': result.drawdown_duration ?? 'N/A',
    },
    {
      'Lợi nhuận khi bắt đầu | kết thúc drawdown': `${formatPriceStake(result.max_drawdown_high)} | ${formatPriceStake(
        result.max_drawdown_low,
      )}`,
    },
    { 'Bắt đầu drawdown': timestampms(result.drawdown_start_ts) },
    { 'Kết thúc drawdown': timestampms(result.drawdown_end_ts) },
    ...walletBalanceMetrics,
    { '___    ': '___' },
    {
      'Cặp tốt nhất': `${result.best_pair.key} ${formatPercent(result.best_pair.profit_total)}`,
    },
    {
      'Cặp tệ nhất': `${result.worst_pair.key} ${formatPercent(result.worst_pair.profit_total)}`,
    },
    { 'Lệnh tốt nhất': bestPair },
    { 'Lệnh tệ nhất': worstPair },
  ];
  return tmp;
}

function capitalizeFirstLetter(str: string): string {
  return str.charAt(0).toUpperCase() + str.slice(1);
}

function formatTradingMode(result: StrategyBacktestResult) {
  if (!result.trading_mode || !result.margin_mode) {
    return {};
  }
  const value =
    result.trading_mode === 'spot'
      ? capitalizeFirstLetter(result.trading_mode)
      : `${capitalizeFirstLetter(result.margin_mode)} ${capitalizeFirstLetter(result.trading_mode)}`;
  return { 'Chế độ giao dịch': value };
}

export function generateBacktestSettingRows(result: StrategyBacktestResult) {
  const formatPriceStake = useFormatPriceStake(
    result.stake_currency_decimals,
    result.stake_currency,
  );
  const tradingMode = formatTradingMode(result);

  return [
    { 'Backtesting từ': timestampms(result.backtest_start_ts) },
    { 'Backtesting đến': timestampms(result.backtest_end_ts) },
    ...(Object.keys(tradingMode).length !== 0 ? [tradingMode] : []),
    {
      'Thời gian chạy BT': humanizeDurationFromSeconds(
        result.backtest_run_end_ts - result.backtest_run_start_ts,
      ),
    },
    { 'Lệnh mở tối đa': result.max_open_trades },
    { 'Khung thời gian': result.timeframe },
    { 'Chi tiết khung thời gian': result.timeframe_detail || 'N/A' },
    { 'Khoảng thời gian': result.timerange },
    { 'Stoploss': formatPercent(result.stoploss, 2) },
    { 'Trailing Stoploss': result.trailing_stop },
    {
      'Kích hoạt trailing khi đạt offset': result.trailing_only_offset_is_reached,
    },
    { 'Trailing Stop dương': formatNumber(result.trailing_stop_positive) },
    {
      'Offset trailing stop dương': formatNumber(result.trailing_stop_positive_offset),
    },
    { 'Stoploss tùy chỉnh': result.use_custom_stoploss },
    { ROI: JSON.stringify(result.minimal_roi) },
    {
      'Dùng tín hiệu thoát': result.use_exit_signal ?? result.use_sell_signal,
    },
    {
      'Chỉ thoát khi có lãi': result.exit_profit_only ?? result.sell_profit_only,
    },
    {
      'Offset thoát có lãi': formatNumber(result.exit_profit_offset ?? result.sell_profit_offset),
    },
    { 'Bật bảo vệ': result.enable_protections },
    {
      'Số dư ban đầu': formatPriceStake(result.starting_balance),
    },
    {
      'Số dư cuối': formatPriceStake(result.final_balance),
    },
    {
      'Số dư stake trung bình': formatPriceStake(result.avg_stake_amount),
    },
    {
      'Tổng khối lượng giao dịch': formatPriceStake(result.total_volume),
    },
  ];
}

